SELECT COUNT(1)
FROM monitor_event
WHERE project_id = #{projectId}
  AND occurred_at  >=  #{startTime}
  AND occurred_at  <=  #{endTime}

SELECT COUNT(1)
FROM monitor_event
WHERE project_id = #{projectId}
  AND occurred_at  >=  #{startTime}
  AND occurred_at  <=  #{endTime}
  AND event_type IN ('js_error', 'promise_rejection', 'console_error', 'resource_error', 'request_error')

SELECT COUNT(1)
FROM monitor_event
WHERE project_id = #{projectId}
  AND occurred_at  >=  #{startTime}
  AND occurred_at  <=  #{endTime}
  AND event_type = 'page_view'

SELECT COUNT(DISTINCT session_id)
FROM monitor_event
WHERE project_id = #{projectId}
  AND occurred_at  >=  #{startTime}
  AND occurred_at  <=  #{endTime}
  AND session_id IS NOT NULL
  AND session_id != ''

SELECT COUNT(DISTINCT user_id)
FROM monitor_event
WHERE project_id = #{projectId}
  AND occurred_at  >=  #{startTime}
  AND occurred_at  <=  #{endTime}
  AND user_id IS NOT NULL
  AND user_id != ''

SELECT COUNT(DISTINCT device_id)
FROM monitor_event
WHERE project_id = #{projectId}
  AND occurred_at  >=  #{startTime}
  AND occurred_at  <=  #{endTime}
  AND device_id IS NOT NULL
  AND device_id != ''

SELECT event_type AS eventType, COUNT(1) AS totalCount
FROM monitor_event
WHERE project_id = #{projectId}
  AND occurred_at  >=  #{startTime}
  AND occurred_at  <=  #{endTime}
GROUP BY event_type
ORDER BY totalCount DESC

SELECT DATE_FORMAT(occurred_at, '%Y-%m-%d %H:00:00') AS bucket,
       COUNT(1) AS totalCount
FROM monitor_event
WHERE issue_id = #{issueId}
  AND occurred_at  >=  #{startTime}
  AND occurred_at  <=  #{endTime}
GROUP BY DATE_FORMAT(occurred_at, '%Y-%m-%d %H:00:00')
ORDER BY bucket ASC

SELECT DATE_FORMAT(occurred_at, '%Y-%m-%d') AS bucket,
       COUNT(1) AS totalCount
FROM monitor_event
WHERE issue_id = #{issueId}
  AND occurred_at  >=  #{startTime}
  AND occurred_at  <=  #{endTime}
GROUP BY DATE_FORMAT(occurred_at, '%Y-%m-%d')
ORDER BY bucket ASC
